4771	<!doctype html>\n<html>\n  <head>\n    <title></title>\n    <style>\n    h1{\n       border:4px solid red; \n        text-align:center;\n        }\n        h2{\n        background-color:red;\n        padding:20px;\n        color:white;\n        text-align:center;\n    </style>\n  </head>\n  <body>\n<h1>Subtraction Calculator</h1>\n<h2>Ingiza namba katika nafasi ya chini, halafu piga \n"calculate!"</h2>\n<center><input id='num1'>\n- <input id='num2'>=\n<span id='output'></span></center>\n<br><center>\n    <button id='calculate'>calculate!</button></center>\n    <!-- Leave this script here at the bottom. Enter your HTML above,\n         AND MAKE SURE TO CHANGE THE CODE BELOW TO MAKE IT\n         SUBTRACT INSTEAD OF ADD.\n    -->\n    <script>\n        document.getElementById('calculate').addEventListener('click',\n          function() {\n             output = document.getElementById('output');\n             num1 = document.getElementById('num1');\n             num2 = document.getElementById('num2');\n             output.innerText = parseInt(num1.value)\n                              - parseInt(num2.value);\n          });\n    </script>\n  </body>\n</html>	2018-04-16 07:22:42.490323-04	2018-04-18 04:17:49.824614-04	24	6	t
