re that starts at 0.\n         var sum=0;\n         Array.prototype.forEach.call(inputs, function(input, index, arr) {\n            // TODO: Add a line here to add input.value to the sum.\n            sum += parseInt(input.value);\n         });\n         // TODO: Add a line here to output the total to the span called 'output'\n         var output = document.getElementById('output');\n         output.innerText=sum;\n       };\n     </script>\n   </body>\n</html>	2018-04-17 06:39:05.943607-04	2018-04-19 06:52:29.952724-04	27	43	t
