COPY nyokatofali_problem (id, name, html_desc, initial_code, verify_code, level) FROM stdin;
52	Sum of Variables form1 to form4	In variable <b>form1</b>, store the number 54.<br/>\r\nIn variable <b>form2</b>, store the number 64.<br/>\r\nIn variable <b>form3</b>, store the number 49.<br/>\r\nIn variable <b>form4</b>, store the number 75.<br/>\r\nFinally, print the sum of all of these variables.	﻿<xml xmlns="http://www.w3.org/1999/xhtml"></xml>	NTPRINT("\\n=== Testing your program... =============================")\r\ntest = 1\r\ntests = [('store 54 in form1', 'form1' in locals() and form1 == 54), ('store 64 in form2', 'form2' in locals() and form2 == 64), ('store 49 in form3', 'form3' in locals() and form3 == 49), ('store 75 in form4', 'form4' in locals() and form4 == 75), ('print the sum of all variables?', PRINTED_LOG.strip() == str(54+64+49+75))]\r\ndef verifier_results():\r\n    NTPRINT('NT_VERIFIER_RESULTS:%d:%d' % (test-1, len(tests)))\r\n    import sys\r\n    sys.exit(0)\r\nfor (task, result) in tests:\r\n    NTPRINT("TEST %d) Did you %s?" % (test, task))\r\n    if result:\r\n        NTPRINT("\\t-> CORRECT")\r\n        test += 1\r\n    else:\r\n        NTPRINT("\\t-> INCORRECT. Try again.")\r\n        verifier_results()\r\nNTPRINT("ALL TESTS PASSED.")\r\nverifier_results()	2
