67	Count all Even Numbers from 1 to n	You have been given a function called <i>countAllEvenNums</i> that takes one variable called <i>n</i>.\r\n<br/>\r\n<br/>Return the number of even numbers from 1 to <i>n</i>. For example, if <i>n</i> is 10, your code should return 5, because there are 5 even numbers from 1 to 10: 2, 4, 6, 8, and 10.	<block type="def" id="d%9jK5xNp[_d~j,,s)Jv" x="251" y="113">\r\n    <field name="funcname">countAllEvenNums</field>\r\n    <field name="funcargs">n</field>\r\n  </block>	import random\r\nNTPRINT("\\n=== Testing your program... =============================")\r\ntest = 1\r\ntests = [random.randint(2, 1000) for _ in range(1, 50)]\r\ndef verifier_results():\r\n    NTPRINT('NT_VERIFIER_RESULTS:%d:%d' % (test-1, len(tests)))\r\n    import sys\r\n    sys.exit(0)\r\nfor num in tests:\r\n    NTPRINT("TEST %d) Checking your answer to %d:" % (test, num))\r\n    response = countAllEvenNums(num)\r\n    answer = 0\r\n    for i in range(1, num + 1):\r\n      answer += 1 if i % 2 == 0 else 0\r\n    if response == answer:\r\n        NTPRINT("\\t-> CORRECT")\r\n        test += 1\r\n    else:\r\n        NTPRINT("\\t-> INCORRECT. You answer '%s'. Try again." % response)\r\n        verifier_results()\r\nNTPRINT("ALL TESTS PASSED.")\r\nverifier_results()	8
